import { CommonModule } from '@angular/common';
import { ChangeDetectionStrategy, Component, OnChanges, input, output, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { NgbDateStruct, NgbInputDatepicker } from '@ng-bootstrap/ng-bootstrap';
import { BadgeComponent, BadgeStatus } from '../badge/badge.component';
import { ButtonComponent, ButtonVariant } from '../button/button.component';
import { WorkCenter } from '../schedule/schedule.component';

export type WorkOrderDrawerMode = 'create' | 'edit';

export interface WorkOrderDrawerValue {
  id?: string;
  name: string;
  workCenterId: string;
  status: BadgeStatus;
  startDate: string;
  endDate: string;
}

@Component({
  selector: 'nao-work-order-drawer',
  standalone: true,
  imports: [CommonModule, FormsModule, NgbInputDatepicker, BadgeComponent, ButtonComponent],
  templateUrl: './work-order-drawer.component.html',
  styleUrl: './work-order-drawer.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class WorkOrderDrawerComponent implements OnChanges {
  readonly mode = input<WorkOrderDrawerMode>('create');
  readonly value = input<WorkOrderDrawerValue | null>(null);
  readonly workCenters = input<WorkCenter[]>([]);

  readonly closed = output<void>();
  readonly saved = output<WorkOrderDrawerValue>();
  readonly statusOpen = signal(false);

  protected readonly ButtonVariant = ButtonVariant;

  protected readonly statuses: Array<{ value: BadgeStatus; label: string }> = [
    { value: BadgeStatus.Open, label: 'Open' },
    { value: BadgeStatus.InProgress, label: 'In progress' },
    { value: BadgeStatus.Complete, label: 'Complete' },
    { value: BadgeStatus.Blocked, label: 'Blocked' },
  ];

  protected draft: WorkOrderDrawerValue = this.emptyDraft();
  protected startDateValue: NgbDateStruct | null = null;
  protected endDateValue: NgbDateStruct | null = null;

  ngOnChanges(): void {
    this.draft = { ...(this.value() ?? this.emptyDraft()) };
    this.startDateValue = this.parseIsoDate(this.draft.startDate);
    this.endDateValue = this.parseIsoDate(this.draft.endDate);
  }

  protected get title(): string {
    return this.mode() === 'edit' ? 'Edit Work Order' : 'Work Order Details';
  }

  protected get submitLabel(): string {
    return this.mode() === 'edit' ? 'Save' : 'Create';
  }

  protected get isInvalid(): boolean {
    return !this.draft.name.trim()
      || !this.draft.workCenterId
      || !this.draft.status
      || !this.draft.startDate
      || !this.draft.endDate
      || this.draft.endDate < this.draft.startDate;
  }

  protected save(): void {
    if (this.isInvalid) {
      return;
    }

    this.saved.emit({ ...this.draft, name: this.draft.name.trim() });
  }

  protected get selectedStatusLabel(): string {
    return this.statuses.find(status => status.value === this.draft.status)?.label ?? 'Select status';
  }

  protected toggleStatus(): void {
    this.statusOpen.update(open => !open);
  }

  protected closeStatus(): void {
    this.statusOpen.set(false);
  }

  protected selectStatus(status: BadgeStatus): void {
    this.draft.status = status;
    this.closeStatus();
  }

  protected setDate(field: 'startDate' | 'endDate', value: NgbDateStruct | null): void {
    if (field === 'startDate') {
      this.startDateValue = value;
    } else {
      this.endDateValue = value;
    }

    this.draft[field] = value ? this.toIsoDate(value) : '';
  }

  private parseIsoDate(value: string): NgbDateStruct | null {
    if (!value) {
      return null;
    }

    const [year, month, day] = value.split('-').map(Number);
    return { year, month, day };
  }

  private toIsoDate(value: NgbDateStruct): string {
    return [
      value.year,
      `${value.month}`.padStart(2, '0'),
      `${value.day}`.padStart(2, '0'),
    ].join('-');
  }

  private emptyDraft(): WorkOrderDrawerValue {
    return {
      name: '',
      workCenterId: '',
      status: BadgeStatus.Open,
      startDate: '',
      endDate: '',
    };
  }
}

